import { Vex } from '@vex_dev/sdk';
import { Mastra } from 'mastra';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  project: 'hr-compliance'
});

const screeningWorkflow = new Mastra.Workflow({
  name: 'resume-screening',
  steps: {
    score: async (input: { resume: string }) => {
      const rawScore = await analyzeResume(input.resume);

      // Vex validation middleware
      const validated = await vex.validate({
        data: rawScore,
        rules: {
          noBiasTerms: ['cultural fit', 'young', 'energetic'],
          scoreRange: { min: 0, max: 100 },
          protectedCharacteristics: ['age', 'gender', 'ethnicity']
        },
        context: { stage: 'initial-screening', role: 'software-engineer' }
      });

      return validated;
    }
  }
});

const hiringWorkflow = new Mastra.Workflow({
  name: 'candidate-journey',
  middleware: [vexMiddleware],
  steps: {
    initialContact: async (candidate) => {
      // Vex enforces disclosure
      await vex.logDecision({
        candidateId: candidate.id,
        decision: 'screened',
        aiUsed: true,
        disclosureSent: true,
        rule: 'nyc-ll144',
        metadata: {
          protectedClassesChecked: true,
          humanReviewRequired: candidate.score > 85
        }
      });

      return {
        ...candidate,
        aiNotice: `This evaluation used AI screening tools as required by NYC Local Law 144.`
      };
    }
  }
});

// Memory retrieval hook
Mastra.useMemoryHook(async (retrievedContext, query) => {
  const cleaned = await vex.sanitizeMemory({
    data: retrievedContext,
    queryContext: query,
    filters: {
      removeStaleSalaryData: true,
      blockProxyDiscrimination: ['zipcode', 'school_name'],
      validateFreshness: { maxAgeDays: 365 }
    }
  });

  // Flag for audit if cleaning required
  if (retrievedContext.length !== cleaned.length) {
    await vex.audit({
      event: 'memory_sanitization',
      details: { removed: retrievedContext.length - cleaned.length },
      complianceRule: 'eeoc-bias-prevention'
    });
  }

  return cleaned;
});
